+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+type ExpressionData<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TData> ? TData
+	: unknown;
+
+type FrameBoundary =
+	| { readonly kind: 'unbounded-preceding' }
+	| { readonly kind: 'current-row' }
+	| { readonly kind: 'unbounded-following' }
+	| { readonly kind: 'preceding'; readonly value: number }
+	| { readonly kind: 'following'; readonly value: number };
+
+export const unboundedPreceding: FrameBoundary = { kind: 'unbounded-preceding' };
+export const currentRow: FrameBoundary = { kind: 'current-row' };
+export const unboundedFollowing: FrameBoundary = { kind: 'unbounded-following' };
+
+function positionalBoundary(name: 'preceding' | 'following', value: number): FrameBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	}
+	return { kind: name, value };
+}
+
+export function preceding(value: number): FrameBoundary {
+	return positionalBoundary('preceding', value);
+}
+
+export function following(value: number): FrameBoundary {
+	return positionalBoundary('following', value);
+}
+
+function boundaryOrder(boundary: FrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded-preceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'current-row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded-following': return Infinity;
+	}
+}
+
+function frameBoundary(boundary: FrameBoundary): SQL {
+	switch (boundary.kind) {
+		case 'unbounded-preceding': return sql.raw('unbounded preceding');
+		case 'current-row': return sql.raw('current row');
+		case 'unbounded-following': return sql.raw('unbounded following');
+		case 'preceding': return sql.raw(`${boundary.value} preceding`);
+		case 'following': return sql.raw(`${boundary.value} following`);
+	}
+}
+
+export interface WindowFrameSpec {
+	from: FrameBoundary;
+	to: FrameBoundary;
+}
+
+export type WindowFrame = SQL;
+
+function createFrame(kind: 'rows' | 'range', spec: WindowFrameSpec): WindowFrame {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return sql`${sql.raw(kind)} between ${frameBoundary(spec.from)} and ${frameBoundary(spec.to)}`;
+}
+
+export function rows(spec: WindowFrameSpec): WindowFrame {
+	return createFrame('rows', spec);
+}
+
+export function range(spec: WindowFrameSpec): WindowFrame {
+	return createFrame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+function array(value: SQLWrapper | SQLWrapper[] | undefined): SQLWrapper[] {
+	return value === undefined ? [] : Array.isArray(value) ? value : [value];
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	const partitionBy = array(spec.partitionBy);
+	const orderBy = array(spec.orderBy);
+	if (partitionBy.length) parts.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	if (orderBy.length) parts.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	if (spec.frame) parts.push(spec.frame);
+	return sql.join(parts, sql` `);
+}
+
+export class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer; received ${value}`);
+	}
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+export function ntile(buckets: number): WindowFunction<number> {
+	positiveInteger('ntile', buckets);
+	return windowFunction('ntile', [sql.raw(String(buckets))]);
+}
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<ExpressionData<T>, null> | ExpressionData<TDefault>>;
