+} from '~/index';
+import { PgDialect, integer, pgTable } from '~/pg-core';
+
+const users = pgTable('users', { id: integer('id') });
+const dialect = new PgDialect();
+
+test('window functions render inline positional arguments and frames', () => {
+	const query = dialect.sqlToQuery(
+		lag(users.id, 0, 0).over({
+			partitionBy: users.id,
+			orderBy: users.id,
+			frame: rows({ from: unboundedPreceding, to: currentRow }),
+		}),
+	);
+	expect(query.sql).toBe('lag("users"."id", 0, $1) over (partition by "users"."id" order by "users"."id" rows between unbounded preceding and current row)');
+	expect(query.params).toEqual([0]);
+	expect(dialect.sqlToQuery(windowCount().over({})).sql).toBe('count(*) over ()');
+});
+
+test('named windows precede order by and references are quoted', () => {
+	const db = drizzle(new RDSDataClient(), { database: '', resourceArn: '', secretArn: '' });
+	const query = db
